let count = 0;
const total = Object.keys(data).length;
console.log(`Uploading ${total} codes to KV namespace: ${KV_NAMESPACE}`);

// Batch upload in chunks of 100
const entries = Object.entries(data);
const BATCH = 100;

for (let i = 0; i < entries.length; i += BATCH) {
  const batch = entries.slice(i, i + BATCH);
  const kvPairs = batch.map(([key, val]) => ({
    key: `proc:${key}`,
    value: JSON.stringify(val)
  }));
  
  // Write batch to temp file
  const fs = require('fs');
  fs.writeFileSync('/tmp/kv_batch.json', JSON.stringify(kvPairs));
  
  try {
    execSync(`wrangler kv:bulk put --binding=${KV_NAMESPACE} /tmp/kv_batch.json`, 
      { stdio: 'pipe' });
    count += batch.length;
    process.stdout.write(`\rUploaded: ${count}/${total}`);
  } catch(e) {
    console.error(`\nError at batch ${i}: ${e.message}`);
  }
}

console.log(`\nDone! ${count} codes uploaded.`);
